  .replace(/(const\s+CELL_SIZE\s*=\s*)(\d+)(\s*;?)/, '$1$2$3')
  .replace(/(function\s+renderSnake\([^)]*\)\s*{[\s\S]*?)(return\b[\s\S]*?}\n)/, (m) => m);

return await space.current.patchWidget("snake-game", {
  edits: [
    {
      search: /canvas\.width\s*=\s*[^;]+;\s*canvas\.height\s*=\s*[^;]+;/,
      replace: (m) => `${m}\nconst MOVE_ANIM_MS = 120;\nlet moveAnimStart = 0;\nlet moveAnimFrom = null;\nlet moveAnimTo = null;`
    },
    {
      search: /function\s+moveSnake\(\)\s*{[\s\S]*?}/,
      replace: (m) => {
        const body = m
          .replace(/snake\.unshift\(\{ x: headX, y: headY \}\);\s*snake\.pop\(\);\s*$/, `snake.unshift({ x: headX, y: headY });\nsnake.pop();\n  moveAnimFrom = { ...snake[1] ?? { x: headX, y: headY } };\n  moveAnimTo = { x: headX, y: headY };\n  moveAnimStart = performance.now();`)
          .replace(/requestAnimationFrame\(gameLoop\);/, `requestAnimationFrame(gameLoop);`);
        return body;
      }
    },
    {
      search: /function\s+drawSnake\(\)\s*{[\s\S]*?}/,
      replace: (m) => `
function drawSnake() {
  const now = performance.now();
  const progress = moveAnimStart ? Math.min(1, (now - moveAnimStart) / MOVE_ANIM_MS) : 1;
  const eased = 1 - Math.pow(1 - progress, 3);

  for (let i = snake.length - 1; i >= 0; i--) {
    const segment = snake[i];
    let x = segment.x;
    let y = segment.y;

    if (i === 0 && moveAnimFrom && moveAnimTo && progress < 1) {
      x = moveAnimFrom.x + (moveAnimTo.x - moveAnimFrom.x) * eased;
      y = moveAnimFrom.y + (moveAnimTo.y - moveAnimFrom.y) * eased;
    } else if (i > 0) {
      const prev = snake[i - 1];
      const curr = snake[i];
      x = curr.x;
      y = curr.y;
    }

    drawSegment(x, y, i === 0);
  }
}
`
    },
    {
      search: /function\s+gameLoop\(\)\s*{[\s\S]*?requestAnimationFrame\(gameLoop\);\s*}/,
      replace: (m) => m.replace(/requestAnimationFrame\(gameLoop\);/, `requestAnimationFrame(gameLoop);`)
    }
  ]
});

