_____javascript
const widget = space.chat.transient.get("snake-game");
if (!widget) throw new Error("snake-game widget not found in transient");
const source = widget.source || widget.code || widget.text || widget.content || "";
const edits = [];

if (typeof source === "string" && source.length) {
  const patched = source
    .replace(/const\s+growth\s*=\s*[^;\n]+;/, `const growth = Math.max(0, snake.growBuffer || 0);`)
    .replace(/snake\.growBuffer\s*=\s*0;/, `snake.growBuffer = Math.max(0, (snake.growBuffer || 0) - 1);`)
    .replace(/segmentSize\s*=\s*[^;\n]+;/, `segmentSize = baseSize + (segmentIndex === 0 ? headBloat : bellyBulge);`)
    .replace(/drawSegment\(([^)]+)\);/g, (m, args) => `drawSegment(${args}, { headBloat, bellyBulge, biteIndex: snake.biteIndex, growth: snake.growBuffer });`)
    .replace(/if\s*\(\s*eatsFood\s*\)\s*\{([\s\S]*?)\}/, (m, body) => {
      if (body.includes("snake.biteIndex")) return m;
      return `if (eatsFood) {\n  snake.growBuffer = (snake.growBuffer || 0) + 4;\n  snake.biteIndex = 0;\n${body}\n}`;
    })
    .replace(/const\s+headBloat\s*=\s*[^;\n]+;/, `const headBloat = 1.18 + Math.min(0.22, (snake.movePhase || 0) * 0.08);`)
    .replace(/const\s+bellyBulge\s*=\s*[^;\n]+;/, `const bellyBulge = 1.0 + Math.min(0.35, (snake.growBuffer || 0) * 0.08);`);

  if (patched !== source) edits.push({ oldText: source, newText: patched });
}

if (!edits.length) {
  const text = String(source);
  throw new Error("Could not identify snake widget source to patch; current transient source length: " + text.length);
}

return await space.current.patchWidget("snake-game", { edits });

