const widget = space.chat.transient.get("snake-game");
const current = typeof widget?.text === "function" ? await widget.text() : widget?.content ?? widget;
const text = String(current);

const replacements = [
  [/transform\s*:\s*translateX\(([^)]+)\)\s*translateY\(([^)]+)\)\s*;/g, 'transform: translate3d($1, $2, 0);'],
  [/transition\s*:\s*none\s*;/g, 'transition: transform 90ms linear;'],
  [/transition\s*:\s*transform\s+[^;]+;/g, 'transition: transform 90ms linear;'],
  [/animation\s*:\s*none\s*;/g, 'animation: moveCell 90ms linear;'],
  [/snake(\.segment|-segment)?\s*\{/g, '$&\n  will-change: transform;\n  transition: transform 90ms linear;'],
];

let next = text;
for (const [from, to] of replacements) next = next.replace(from, to);

if (next === text) {
  next = text
    .replace(/(function|const|let)\s+moveSnake[^]*?\{/, m => m)
    .replace(/(grid|cell|segment|snake-head)[^{}]*\{[^}]*\}/g, s => {
      if (/transition|will-change/.test(s)) return s;
      return s.replace(/\{/, '{\n  transition: transform 90ms linear;\n  will-change: transform;');
    });
}

return await space.current.patchWidget("snake-game", {
  edits: [
    {
      type: "replaceAll",
      text: next
    }
  ]
});

