  [/background(?:-color)?:\s*[^;]+;/gi, "background-color: #c8e6c9;"],
  [/background(?:-color)?:\s*transparent;/gi, "background-color: #c8e6c9;"],
  [/color:\s*[^;]+;/gi, "color: #1b5e20;"],
  [/font-family:\s*[^;]+;/gi, "font-family: 'Courier New', monospace;"],
  [/box-shadow:\s*[^;]+;/gi, "box-shadow: inset 0 0 0 2px #2e7d32, 0 0 10px rgba(46, 125, 50, 0.25);"],
];

let updated = text;
for (const [re, to] of replacements) updated = updated.replace(re, to);

if (updated === text) {
  const insertCss = `
/* Nokia-like display */
.snake-game, .snake-game canvas, .snake-game * {
  background-color: #c8e6c9 !important;
  color: #1b5e20 !important;
  font-family: 'Courier New', monospace !important;
}
.snake-game {
  box-shadow: inset 0 0 0 2px #2e7d32, 0 0 10px rgba(46, 125, 50, 0.25) !important;
}
`.trim();

  if (text.includes("</style>")) {
    updated = text.replace("</style>", `${insertCss}\n</style>`);
  } else {
    updated = text + "\n\n" + insertCss;
  }
}

if (updated === text) return "No changes made";

return await space.current.patchWidget("snake-game", { edits: [{ from: text, to: updated }] });

