const widget = space.chat.transient.get("snake-game");
if (!widget) return "snake-game not in transient";
const source = typeof widget === "string" ? widget : (widget.text || widget.source || JSON.stringify(widget));
const updated = source
  .replace(/const\s+STEP\s*=\s*\d+;?/g, 'const STEP = 1;')
  .replace(/setInterval\(\s*tick\s*,\s*[^)]+\)/g, 'requestAnimationFrame(loop)')
  .replace(/function tick\(\)\s*{[\s\S]*?}/, match => match)
  .replace(/render\(\);/g, `render();\n`)
  .replace(/let lastTime = 0;[\s\S]*?function render\(\)/, `let lastTime = 0;
let animProgress = 0;
let renderPrev = null;
let renderNext = null;

function render()`)
  .replace(/function moveSnake\(\)\s*{/, `function moveSnake() {
  renderPrev = snake.map(p => ({ x: p.x, y: p.y }));`)
  .replace(/snake\.unshift\(\{ x: nextX, y: nextY \}\);\s*snake\.pop\(\);/, `snake.unshift({ x: nextX, y: nextY });
  snake.pop();
  renderNext = snake.map(p => ({ x: p.x, y: p.y }));
  animProgress = 0;`)
  .replace(/function drawSnake\(\)[\s\S]*?function drawFood\(\)/, `function drawSnake(ctx) {
  const eased = Math.min(1, Math.max(0, animProgress));
  for (let i = 0; i < snake.length; i++) {
    const prev = renderPrev && renderPrev[i] ? renderPrev[i] : snake[i];
    const next = renderNext && renderNext[i] ? renderNext[i] : snake[i];
    const x = prev.x + (next.x - prev.x) * eased;
