const widget = await space.current.readWidget("snake-game");
const text = widget?.content ?? widget?.text ?? widget;
let src = String(text);

const replacements = [
  [
    /const\s+SPEED\s*=\s*([^\n;]+);/g,
    'const SPEED = 140;'
  ],
  [
    /setInterval\(\s*gameLoop\s*,\s*([^)\n]+)\s*\)/g,
    'requestAnimationFrame(gameLoop)'
  ],
  [
    /function\s+gameLoop\s*\(\s*\)\s*\{[\s\S]*?\n\}/g,
    `function gameLoop() {
  const now = performance.now();
  if (!window.__snakeLast) window.__snakeLast = now;
  const dt = now - window.__snakeLast;
  if (!window.__snakeAnim) window.__snakeAnim = { progress: 1, from: null, to: null };
  if (dt < SPEED) return;
  window.__snakeLast = now;
  stepSnake();
  window.__snakeAnim.progress = 0;
  requestAnimationFrame(animateFrame);
}`
  ],
  [
    /render\(\s*\)\s*;/g,
    'animateFrame();'
  ]
];

for (const [pattern, replacement] of replacements) src = src.replace(pattern, replacement);

if (!/function\s+animateFrame\s*\(/.test(src)) {
  src += `

function animateFrame() {
  const anim = window.__snakeAnim || { progress: 1 };
  anim.progress = Math.min(1, (anim.progress ?? 0) + 0.2);
  window.__snakeAnim = anim;
  render();
  if (anim.progress < 1) requestAnimationFrame(animateFrame);
}

function lerp(a, b, t) {
  return a + (b - a) * t;
}

function drawSmoothSnake(ctx, cellSize, snake) {
  const anim = window.__snakeAnim || { progress: 1 };
  const t = anim.progress ?? 1;
  const parts = snake.map((seg, i) => {
    const prev = anim.from?.[i] ?? seg;
    const next = anim.to?.[i] ?? seg;
    return {
      x: lerp(prev.x, next.x, t),
      y: lerp(prev.y, next.y, t)
    };
  });
  for (const p of parts) {
    ctx.beginPath();
    ctx.arc((p.x + 0.5) * cellSize, (p.y + 0.5) * cellSize, cellSize * 0.42, 0, Math.PI * 2);
    ctx.fill();
  }
}
`;
}

src = src.replace(
  /function\s+stepSnake\s*\(\s*\)\s*\{[\s\S]*?\n\}/g,
  `function stepSnake() {
  const anim = window.__snakeAnim || { progress: 1, from: null, to: null };
  anim.from = snake.map(s => ({ ...s }));
  const next = computeNextSnakeState();
  anim.to = next.snake.map(s => ({ ...s }));
  window.__snakeAnim = anim;
  snake = next.snake;
  food = next.food;
  score = next.score;
}`
);

src = src.replace(
  /function\s+render\s*\(\s*\)\s*\{[\s\S]*?\n\}/g,
  `function render() {
  ctx.clearRect(0, 0, canvas.width, canvas.height);
  drawBoard();
  drawFood();
  drawSmoothSnake(ctx, cellSize, snake);
  drawHud();
}`
);

